create extension if not exists pgcrypto;
create schema if not exists private;
revoke all on schema private from public, anon, authenticated;
create type public.recipe_status as enum ('draft','needs_review','ready','archived');
create type public.import_status as enum ('pending','validating','checking_limit','checking_cache','extracting','transcribing','structuring','validating_output','saving','needs_manual_input','needs_review','completed','failed','cancelled');
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,email text,full_name text,avatar_url text,plan text not null default 'free' check(plan in('free','pro')),plan_renewed_at timestamptz,theme_preference text not null default 'system' check(theme_preference in('light','dark','system')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.recipe_import_jobs(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles(id) on delete cascade,input_type text not null check(input_type in('url','text','audio')),idempotency_key text,source_url text,normalized_url text,source_platform text,raw_text text,audio_path text,status public.import_status not null default 'pending',current_stage text,provider text,model_id text,parser_version text not null default '1',schema_version text not null default '1',attempt_count int not null default 0,fallback_reason text,error_code text,error_message text,recipe_id uuid,started_at timestamptz,completed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(user_id,idempotency_key));
create table public.recipes(id uuid primary key default gen_random_uuid(),user_id uuid not null default auth.uid() references public.profiles(id) on delete cascade,import_job_id uuid references public.recipe_import_jobs(id) on delete set null,title text not null,description text,prep_time_minutes int check(prep_time_minutes>=0),cook_time_minutes int check(cook_time_minutes>=0),total_time_minutes int check(total_time_minutes>=0),servings numeric check(servings>=0),status public.recipe_status not null default 'draft',source_url text,source_url_normalized text,source_platform text,parsing_confidence text check(parsing_confidence in('high','medium','low')),warnings jsonb not null default '[]',parser_version text,schema_version text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
alter table public.recipe_import_jobs add constraint recipe_import_jobs_recipe_fk foreign key(recipe_id) references public.recipes(id) on delete set null;
create table public.recipe_ingredients(id uuid primary key default gen_random_uuid(),recipe_id uuid not null references public.recipes(id) on delete cascade,name text not null,normalized_name text,quantity_text text,quantity numeric check(quantity>=0),unit text,normalized_unit text,notes text,sector text not null default 'Outros',section text,position int not null default 0,created_at timestamptz not null default now());
create table public.recipe_steps(id uuid primary key default gen_random_uuid(),recipe_id uuid not null references public.recipes(id) on delete cascade,position int not null,instruction text not null,section text,created_at timestamptz not null default now());
create table public.categories(id uuid primary key default gen_random_uuid(),user_id uuid not null default auth.uid() references public.profiles(id) on delete cascade,name text not null,color text,created_at timestamptz not null default now(),unique(user_id,name));
create table public.recipe_categories(recipe_id uuid references public.recipes(id) on delete cascade,category_id uuid references public.categories(id) on delete cascade,primary key(recipe_id,category_id));
create table public.shopping_lists(id uuid primary key default gen_random_uuid(),user_id uuid not null default auth.uid() references public.profiles(id) on delete cascade,name text not null default 'Lista de compras',status text not null default 'active' check(status in('active','completed','archived')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.shopping_list_items(id uuid primary key default gen_random_uuid(),shopping_list_id uuid not null references public.shopping_lists(id) on delete cascade,name text not null,normalized_name text,quantity numeric,unit text,sector text not null default 'Outros',checked boolean not null default false,position int not null default 0,created_at timestamptz not null default now());
create table public.shopping_list_item_sources(id uuid primary key default gen_random_uuid(),item_id uuid not null references public.shopping_list_items(id) on delete cascade,recipe_id uuid not null references public.recipes(id) on delete cascade,ingredient_id uuid references public.recipe_ingredients(id) on delete set null,original_quantity numeric,original_unit text);
create table public.usage_events(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles(id) on delete cascade,job_id uuid not null unique references public.recipe_import_jobs(id) on delete cascade,event_type text not null default 'completed_import',created_at timestamptz not null default now());
create table private.url_cache(id uuid primary key default gen_random_uuid(),normalized_url text not null,parser_version text not null,schema_version text not null,recipe_json jsonb not null,content_hash text,model_id text,validation_status text not null,expires_at timestamptz not null,last_used_at timestamptz,created_at timestamptz not null default now(),unique(normalized_url,parser_version,schema_version));
create index recipes_user_created_idx on public.recipes(user_id,created_at desc);create index jobs_user_status_idx on public.recipe_import_jobs(user_id,status);create index ingredients_recipe_idx on public.recipe_ingredients(recipe_id,position);create index usage_user_created_idx on public.usage_events(user_id,created_at);
alter table public.profiles enable row level security;alter table public.recipe_import_jobs enable row level security;alter table public.recipes enable row level security;alter table public.recipe_ingredients enable row level security;alter table public.recipe_steps enable row level security;alter table public.categories enable row level security;alter table public.recipe_categories enable row level security;alter table public.shopping_lists enable row level security;alter table public.shopping_list_items enable row level security;alter table public.shopping_list_item_sources enable row level security;alter table public.usage_events enable row level security;
create policy profiles_own on public.profiles for all to authenticated using((select auth.uid())=id) with check((select auth.uid())=id);
create policy jobs_own_select on public.recipe_import_jobs for select to authenticated using((select auth.uid())=user_id);
create policy recipes_own on public.recipes for all to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);
create policy ingredients_own on public.recipe_ingredients for all to authenticated using(exists(select 1 from public.recipes r where r.id=recipe_id and r.user_id=(select auth.uid()))) with check(exists(select 1 from public.recipes r where r.id=recipe_id and r.user_id=(select auth.uid())));
create policy steps_own on public.recipe_steps for all to authenticated using(exists(select 1 from public.recipes r where r.id=recipe_id and r.user_id=(select auth.uid()))) with check(exists(select 1 from public.recipes r where r.id=recipe_id and r.user_id=(select auth.uid())));
create policy categories_own on public.categories for all to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);
create policy recipe_categories_own on public.recipe_categories for all to authenticated using(exists(select 1 from public.recipes r where r.id=recipe_id and r.user_id=(select auth.uid()))) with check(exists(select 1 from public.recipes r where r.id=recipe_id and r.user_id=(select auth.uid())));
create policy shopping_lists_own on public.shopping_lists for all to authenticated using((select auth.uid())=user_id) with check((select auth.uid())=user_id);
create policy shopping_items_own on public.shopping_list_items for all to authenticated using(exists(select 1 from public.shopping_lists l where l.id=shopping_list_id and l.user_id=(select auth.uid()))) with check(exists(select 1 from public.shopping_lists l where l.id=shopping_list_id and l.user_id=(select auth.uid())));
create policy shopping_sources_own on public.shopping_list_item_sources for all to authenticated using(exists(select 1 from public.shopping_list_items i join public.shopping_lists l on l.id=i.shopping_list_id where i.id=item_id and l.user_id=(select auth.uid()))) with check(exists(select 1 from public.shopping_list_items i join public.shopping_lists l on l.id=i.shopping_list_id where i.id=item_id and l.user_id=(select auth.uid())));
create policy usage_own_select on public.usage_events for select to authenticated using((select auth.uid())=user_id);
create or replace function private.handle_new_user() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.profiles(id,email,full_name,avatar_url) values(new.id,new.email,new.raw_user_meta_data->>'full_name',new.raw_user_meta_data->>'avatar_url');return new;end$$;
create trigger on_auth_user_created after insert on auth.users for each row execute function private.handle_new_user();
create or replace function public.get_monthly_usage() returns bigint language sql stable security invoker set search_path='' as $$select count(*) from public.usage_events where user_id=(select auth.uid()) and created_at>=date_trunc('month',now())$$;grant execute on function public.get_monthly_usage() to authenticated;
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('recipe-audio','recipe-audio',false,26214400,array['audio/mpeg','audio/mp4','audio/webm','audio/wav','audio/ogg']) on conflict(id) do nothing;
create policy audio_insert on storage.objects for insert to authenticated with check(bucket_id='recipe-audio' and (storage.foldername(name))[1]=(select auth.uid())::text);
create policy audio_select on storage.objects for select to authenticated using(bucket_id='recipe-audio' and (storage.foldername(name))[1]=(select auth.uid())::text);
create policy audio_delete on storage.objects for delete to authenticated using(bucket_id='recipe-audio' and (storage.foldername(name))[1]=(select auth.uid())::text);
alter publication supabase_realtime add table public.recipe_import_jobs;
